17→
18→  const initials = fallback
19→    .split(" ")
20→    .map((n) => n[0])
21→    .join("")
22→    .toUpperCase()
23→    .slice(0, 2)
24→
25→  if (src) {
26→    return (
27→      <img
28→        src={src}
29→        alt={alt || fallback}
30→        className={cn("rounded-full object-cover", sizes[size], className)}
31→      />
32→    )
33→  }
34→
35→  return (
36→    <div
37→      className={cn(
38→        "inline-flex items-center justify-center rounded-full bg-primary/20 text-primary font-medium",
39→        sizes[size],
40→        className
41→      )}
42→      {...props}
43→    >
44→      {initials}
45→    </div>
46→  )
47→}
