 1→/**
 2→ * Structured error handling for API routes
 3→ */
 4→
 5→export class AppError extends Error {
 6→  constructor(
 7→    message: string,
 8→    public statusCode: number = 500,
 9→    public code: string = "INTERNAL_ERROR"
10→  ) {
11→    super(message)
12→    this.name = "AppError"
13→  }
14→}
15→
16→export class AuthError extends AppError {
17→  constructor(message = "Non authentifie") {
18→    super(message, 401, "UNAUTHORIZED")
19→  }
20→}
21→
22→export class ForbiddenError extends AppError {
23→  constructor(message = "Acces refuse") {
24→    super(message, 403, "FORBIDDEN")
25→  }
26→}
27→
28→export class NotFoundError extends AppError {
29→  constructor(message = "Ressource introuvable") {
30→    super(message, 404, "NOT_FOUND")
31→  }
32→}
33→
34→export class ValidationError extends AppError {
35→  constructor(message: string) {
36→    super(message, 400, "VALIDATION_ERROR")
37→  }
38→}
39→
40→export class RateLimitError extends AppError {
41→  constructor(message = "Trop de requetes, reessayez plus tard") {
42→    super(message, 429, "RATE_LIMIT_EXCEEDED")
43→  }
44→}
45→
46→/**
47→ * Format error for API response
48→ */
49→export function formatApiError(error: unknown): {
50→  status: number
51→  body: { error: string; code: string }
52→} {
53→  if (error instanceof AppError) {
54→    return {
55→      status: error.statusCode,
56→      body: { error: error.message, code: error.code },
57→    }
58→  }
59→
60→  console.error("Unhandled error:", error)
61→  return {
62→    status: 500,
63→    body: { error: "Erreur interne du serveur", code: "INTERNAL_ERROR" },
64→  }
65→}
